import{_ as a,o as t,c as b,j as r,a as s,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"召唤鸭鸭之剑","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/6.可升级/召唤鸭鸭之剑.md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/6.可升级/召唤鸭鸭之剑.md"}'),o={name:"4.资源分区/7.物品与装备/2.武器/近战武器/6.可升级/召唤鸭鸭之剑.md"};function p(d,e,_,l,i,c){return t(),b("div",null,[...e[0]||(e[0]=[r("h1",{id:"召唤鸭鸭之剑",tabindex:"-1"},[s("召唤鸭鸭之剑 "),r("a",{class:"header-anchor",href:"#召唤鸭鸭之剑","aria-label":'Permalink to "召唤鸭鸭之剑"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风023元旦版")])])],-1),n('<h1 id="召唤鸭鸭之剑-1" tabindex="-1">召唤鸭鸭之剑 <a class="header-anchor" href="#召唤鸭鸭之剑-1" aria-label="Permalink to &quot;召唤鸭鸭之剑&quot;">​</a></h1><p>召唤鸭鸭之剑<br> C+1000<br> 奇物<br> 这是一把黄不溜秋，剑身毛绒绒的短剑，剑身只有不到半米长，宽约一掌，摸上去不管是剑柄还是剑身都很毛茸茸，很舒服！<br> 但它能随时召唤一只鸭鸭！想想看，这是不是很酷？</p><p>武器伤害:0<br> 专业/分类：剑<br> 体积:2</p><p>【召唤鸭鸭】你可以在你触及范围内使用一个标准动作，随意召唤一只普普通通的鸭鸭，一般来说，这些鸭鸭最多存在12只，它们会把你当成母亲，紧紧跟着你。<br> 这些鸭鸭只是一个鸭子，每次毛发性别都将随机生成，但它就是一只普普通通的鸭子，什么都做不了，除了发出嘎嘎的声音。</p><p>【鸭鸭反派】当然你可以是邪恶的鸭鸭大反派！在触及范围敌人体内一些关键部位生成一只鸭鸭！<br> 如果对方是正常生物，且有一套正常的呼吸和消化在体内，那么召唤的鸭鸭将足以<br> 致命。<br> 目前可生成的部位：<br> 【食道】生成：对方将获得1点不可豁免的恶心，可叠加，在生成的这回合内，对方可以以一个移动动作来将鸭子吐出来抵消掉这种负面状态，如果不吐就会发现自己脖子越来越大（？）。<br> 【消化部分（胃，肠子，X门）】对方将获得1点不可豁免的剧痛，可叠加，在生成的回合内，对方花费一个标准动作将体内鸭鸭排出，否则会发现自己屁股/肚子越来越大（？）。<br> PS:如果对方是一些消化极强的怪物，很可能这种鸭鸭只是给对方的血食或者补药，一切以st判定为准。<br> 比如：异形，钻地蠕虫等……</p><p>进阶：<br> 超级召唤鸭鸭之剑<br> S+8000<br> 奇物<br> 【召唤鸭鸭】和原来特性一样，但不再限制鸭鸭数量，并且一次可以额外生成48只。<br> 【鸭鸭反派】和原来一样，但可以随意生成了现在这些鸭鸭可以在目标的任意部位生成，不论是眼眶，血管，还是鼻孔里。<br> 这些鸭鸭的突然出现会使一些生物原有的身体部位被撑爆，碎裂开来！<br> 召唤的鸭鸭一旦高于目标体积2倍，对方就必须进行一次强韧豁免，这次DC和你在对方体内召唤多少只鸭鸭为准，如果没有成功，则被撑爆而亡。这视为一种SS级创伤来源的即死效果。</p><p>鸭鸭<br> 随从<br> 一只普普通通的鸭子，也不会讲话，无法攻击和防御，触之即死，碰之即伤，也没有豁免，唯一的优点是肉质鲜美和能发出嘎嘎的声音。<br> 体积:1<br> 生命值:6<br> 速度：6</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',9)])])}const m=a(o,[["render",p]]);export{f as __pageData,m as default};
